mapper.select:
SELECT admin_id as adminId, name, phone, role_id as roleId, status, fail_count as failCount, created_at as createdAt, updated_at as updatedAt FROM admin_user WHERE 1=1
AND (admin_id LIKE CONCAT('%', #{search}, '%') OR name LIKE CONCAT('%', #{search}, '%'))
AND role_id = #{role}
AND status = #{status}
ORDER BY CASE role_id WHEN 'SUPER' THEN 1 WHEN 'PROD' THEN 2 WHEN 'SALES' THEN 3 WHEN 'MATERIAL' THEN 4 ELSE 5 END, admin_id ASC

